import { useState, useEffect } from 'react';
import API from '../services/axios';

const T = "-apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Segoe UI', sans-serif";
const GOLD = '#D4AF37';

const ANIM = `
  @import url('https://fonts.googleapis.com/css2?family=Sora:wght@400;600;700&family=Space+Mono:wght@400;700&display=swap');
  @keyframes slideUp  { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:translateY(0)} }
  @keyframes fadeUp   { from{opacity:0;transform:translateY(16px)} to{opacity:1;transform:translateY(0)} }
  @keyframes spin     { to{transform:rotate(360deg)} }
  @keyframes checkPop { 0%{transform:scale(0)} 60%{transform:scale(1.2)} 100%{transform:scale(1)} }
  @keyframes pulse    { 0%,100%{box-shadow:0 0 0 0 rgba(212,175,55,0.5)} 70%{box-shadow:0 0 0 12px rgba(212,175,55,0)} }
  input::placeholder { color: #333; }
  select option { background: #111; }
`;

function formatCard(v)   { return v.replace(/\D/g,'').slice(0,16).replace(/(.{4})/g,'$1 ').trim(); }
function formatExpiry(v) { const x=v.replace(/\D/g,'').slice(0,4); return x.length>=2?x.slice(0,2)+'/'+x.slice(2):x; }
function detectBrand(n) {
  const s=(n||'').replace(/\s/g,'');
  if(/^4/.test(s))      return {label:'VISA',  gradient:'linear-gradient(135deg,#0a0f3d,#0d2a8a,#1a4fd6)'};
  if(/^5[1-5]/.test(s)) return {label:'MC',    gradient:'linear-gradient(135deg,#3d0000,#8b0000,#c0392b)'};
  if(/^6/.test(s))      return {label:'RuPay', gradient:'linear-gradient(135deg,#001a0d,#004d1a,#006400)'};
  if(/^3[47]/.test(s))  return {label:'AMEX',  gradient:'linear-gradient(135deg,#001a33,#003d80,#005cbf)'};
  return {label:'', gradient:'linear-gradient(135deg,#1a1400,#2e2400,#3d3000)'};
}

function CardVisual({ number, name, expiry, cvv, flipped }) {
  const brand = detectBrand(number);
  const raw   = (number||'').replace(/\s/g,'').padEnd(16,'•');
  const parts = [raw.slice(0,4),raw.slice(4,8),raw.slice(8,12),raw.slice(12,16)];
  return (
    <div style={{perspective:'1000px',width:'100%',maxWidth:'360px',margin:'0 auto 2rem',height:'200px'}}>
      <div style={{width:'100%',height:'100%',position:'relative',transformStyle:'preserve-3d',transition:'transform 0.6s ease',transform:flipped?'rotateY(180deg)':'rotateY(0deg)'}}>
        {/* Front */}
        <div style={{position:'absolute',inset:0,backfaceVisibility:'hidden',WebkitBackfaceVisibility:'hidden',borderRadius:'20px',background:brand.gradient,padding:'1.6rem',boxShadow:'0 20px 60px rgba(0,0,0,0.6)',border:'1px solid rgba(212,175,55,0.3)',overflow:'hidden'}}>
          <div style={{position:'absolute',top:'-40px',right:'-40px',width:'180px',height:'180px',borderRadius:'50%',background:'rgba(212,175,55,0.07)',pointerEvents:'none'}}/>
          <div style={{position:'absolute',bottom:'-30px',left:'-20px',width:'140px',height:'140px',borderRadius:'50%',background:'rgba(255,255,255,0.03)',pointerEvents:'none'}}/>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'1.6rem',position:'relative'}}>
            <div style={{width:'42px',height:'30px',borderRadius:'6px',background:'linear-gradient(135deg,#D4AF37,#F0D060)',boxShadow:'0 2px 8px rgba(212,175,55,0.4)'}}/>
            <span style={{color:'rgba(212,175,55,0.9)',fontFamily:"'Space Mono',monospace",fontWeight:'700',fontSize:'1rem',letterSpacing:'1px'}}>{brand.label}</span>
          </div>
          <p style={{color:'rgba(255,255,255,0.92)',fontFamily:"'Space Mono',monospace",fontSize:'1.05rem',letterSpacing:'3px',margin:'0 0 1.4rem',textShadow:'0 2px 4px rgba(0,0,0,0.4)',position:'relative'}}>{parts.join(' ')}</p>
          <div style={{display:'flex',justifyContent:'space-between',position:'relative'}}>
            <div>
              <p style={{color:'rgba(255,255,255,0.4)',fontSize:'0.6rem',margin:'0 0 2px',fontFamily:"'Sora',sans-serif",letterSpacing:'2px'}}>CARD HOLDER</p>
              <p style={{color:'white',fontFamily:"'Sora',sans-serif",fontWeight:'600',fontSize:'0.85rem',margin:0,textTransform:'uppercase'}}>{name||'YOUR NAME'}</p>
            </div>
            <div style={{textAlign:'right'}}>
              <p style={{color:'rgba(255,255,255,0.4)',fontSize:'0.6rem',margin:'0 0 2px',fontFamily:"'Sora',sans-serif",letterSpacing:'2px'}}>EXPIRES</p>
              <p style={{color:'white',fontFamily:"'Space Mono',monospace",fontWeight:'700',fontSize:'0.85rem',margin:0}}>{expiry||'MM/YY'}</p>
            </div>
          </div>
        </div>
        {/* Back */}
        <div style={{position:'absolute',inset:0,backfaceVisibility:'hidden',WebkitBackfaceVisibility:'hidden',borderRadius:'20px',background:brand.gradient,transform:'rotateY(180deg)',border:'1px solid rgba(212,175,55,0.3)',overflow:'hidden'}}>
          <div style={{width:'100%',height:'44px',background:'rgba(0,0,0,0.5)',marginTop:'30px'}}/>
          <div style={{padding:'1rem 1.6rem',display:'flex',justifyContent:'flex-end',alignItems:'center',gap:'12px',marginTop:'10px'}}>
            <div style={{flex:1,height:'36px',background:'rgba(255,255,255,0.08)',borderRadius:'4px'}}/>
            <div style={{background:'rgba(212,175,55,0.15)',border:'1px solid rgba(212,175,55,0.4)',borderRadius:'6px',padding:'6px 18px'}}>
              <p style={{color:'#D4AF37',fontFamily:"'Space Mono',monospace",fontWeight:'700',fontSize:'0.9rem',margin:0}}>{cvv?'•'.repeat(cvv.length):'•••'}</p>
            </div>
          </div>
          <p style={{textAlign:'center',color:'rgba(255,255,255,0.35)',fontSize:'0.65rem',fontFamily:"'Sora',sans-serif",letterSpacing:'1px'}}>CVV / CVC</p>
        </div>
      </div>
    </div>
  );
}

const UPI_APPS = [
  {id:'gpay',    label:'GPay',    color:'#4285F4', emoji:'🔵'},
  {id:'phonepe', label:'PhonePe', color:'#7B2FBE', emoji:'🟣'},
  {id:'paytm',   label:'Paytm',   color:'#00BAF2', emoji:'🔷'},
  {id:'bhim',    label:'BHIM',    color:'#FF6600', emoji:'🟠'},
];
const BANKS = ['State Bank of India','HDFC Bank','ICICI Bank','Axis Bank','Kotak Mahindra','Punjab National Bank','Bank of Baroda','Canara Bank'];

function PaymentModal({ booking, onClose, onSuccess }) {
  const [method, setMethod] = useState('card');
  const [step, setStep]     = useState(1);
  const [flipped, setFlipped] = useState(false);
  const [txnId]             = useState('TXN'+Date.now());
  const [card, setCard]     = useState({number:'',name:'',expiry:'',cvv:''});
  const [errors, setErrors] = useState({});
  const [upiId, setUpiId]   = useState('');
  const [upiApp, setUpiApp] = useState('');
  const [bank, setBank]     = useState('');

  const amount = booking?.totalAmount || booking?.totalPrice || booking?.amount || 0;

  const validate = () => {
    const e = {};
    if (method==='card') {
      if ((card.number||'').replace(/\s/g,'').length<16) e.number='Enter valid 16-digit number';
      if (!(card.name||'').trim()) e.name='Enter cardholder name';
      if ((card.expiry||'').length<5) e.expiry='Enter valid MM/YY';
      if ((card.cvv||'').length<3) e.cvv='Enter valid CVV';
    } else if (method==='upi') {
      if (!upiApp && !upiId.trim()) e.upi='Select a UPI app or enter UPI ID';
    } else if (method==='netbanking') {
      if (!bank) e.bank='Please select your bank';
    }
    setErrors(e);
    return Object.keys(e).length===0;
  };

  const handlePay = async () => {
    if (!validate()) return;
    setStep(3);
    await new Promise(r=>setTimeout(r,2500));
    try {
      await API.post('/payments',{booking:booking._id,amount,paymentMethod:method,transactionId:txnId,status:'success'});
    } catch {}
    setStep(4);
  };

  const inp = (err) => ({
    width:'100%', padding:'13px 16px',
    border:`1.5px solid ${err?'#FF453A':'rgba(255,255,255,0.1)'}`,
    borderRadius:'12px', outline:'none', fontSize:'0.9rem',
    fontFamily:"'Sora',sans-serif", color:'#fff',
    background:'#111', transition:'border-color 0.2s',
  });
  const lbl = {display:'block',color:'#555',fontSize:'0.72rem',fontWeight:'600',marginBottom:'6px',letterSpacing:'1px',fontFamily:"'Sora',sans-serif"};

  /* ── Processing ── */
  if (step===3) return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.92)',zIndex:3000,display:'flex',alignItems:'center',justifyContent:'center',fontFamily:"'Sora',sans-serif"}}>
      <div style={{textAlign:'center',animation:'fadeIn 0.4s ease'}}>
        <div style={{width:'72px',height:'72px',border:'4px solid #1a1a1a',borderTop:`4px solid ${GOLD}`,borderRadius:'50%',margin:'0 auto 1.5rem',animation:'spin 0.8s linear infinite'}}/>
        <h3 style={{color:'#fff',fontWeight:'700',fontSize:'1.2rem',margin:'0 0 0.4rem',fontFamily:"'Sora',sans-serif"}}>Processing Payment...</h3>
        <p style={{color:'#555',fontSize:'0.85rem',fontFamily:"'Sora',sans-serif"}}>Please do not close this window</p>
        <p style={{color:GOLD,fontSize:'0.8rem',marginTop:'0.5rem',fontFamily:"'Space Mono',monospace"}}>₹{amount} • {booking?.event?.name||'Event'}</p>
      </div>
    </div>
  );

  /* ── Success ── */
  if (step===4) return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.92)',zIndex:3000,display:'flex',alignItems:'center',justifyContent:'center',fontFamily:"'Sora',sans-serif",padding:'2rem'}}>
      <div style={{background:'#0d0d0d',borderRadius:'28px',padding:'3rem 2.5rem',maxWidth:'440px',width:'100%',textAlign:'center',boxShadow:'0 30px 80px rgba(0,0,0,0.8)',border:'1px solid rgba(255,255,255,0.08)',animation:'slideUp 0.5s ease'}}>
        <div style={{width:'80px',height:'80px',background:'rgba(48,209,88,0.1)',border:'1px solid rgba(48,209,88,0.3)',borderRadius:'50%',display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto 1.5rem',fontSize:'2rem',color:'#30D158',animation:'checkPop 0.5s ease 0.2s both'}}>✓</div>
        <h2 style={{color:'#fff',fontSize:'1.6rem',fontWeight:'700',margin:'0 0 0.4rem',fontFamily:"'Sora',sans-serif"}}>Payment Successful!</h2>
        <p style={{color:'#555',fontSize:'0.88rem',margin:'0 0 2rem',fontFamily:"'Sora',sans-serif"}}>Your booking is confirmed</p>
        <div style={{background:'#111',borderRadius:'16px',padding:'1.4rem',marginBottom:'1.5rem',textAlign:'left',border:'1px solid rgba(255,255,255,0.06)'}}>
          {[
            ['Amount Paid',   `₹${amount}`],
            ['Payment Method',method==='card'?'💳 Card':method==='upi'?'📱 UPI':'🏦 Net Banking'],
            ['Transaction ID',txnId],
            ['Status',        '✅ Success'],
          ].map(([label,value],i)=>(
            <div key={i} style={{display:'flex',justifyContent:'space-between',padding:'8px 0',borderBottom:i<3?'1px solid rgba(255,255,255,0.06)':'none',gap:'1rem'}}>
              <span style={{color:'#555',fontSize:'0.8rem',flexShrink:0,fontFamily:"'Sora',sans-serif"}}>{label}</span>
              <span style={{color:label==='Amount Paid'?GOLD:label==='Status'?'#30D158':'#fff',fontWeight:'600',fontSize:'0.82rem',textAlign:'right',fontFamily:label==='Transaction ID'?"'Space Mono',monospace":"'Sora',sans-serif",wordBreak:'break-all'}}>{String(value)}</span>
            </div>
          ))}
        </div>
        <button onClick={()=>{onSuccess();onClose();}} style={{width:'100%',padding:'14px',background:GOLD,color:'#000',border:'none',borderRadius:'14px',cursor:'pointer',fontWeight:'700',fontSize:'0.95rem',fontFamily:"'Sora',sans-serif",boxShadow:'0 8px 24px rgba(212,175,55,0.3)'}}>
          Done 🎟️
        </button>
      </div>
    </div>
  );

  /* ── Main Form ── */
  return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.92)',zIndex:3000,display:'flex',alignItems:'center',justifyContent:'center',fontFamily:"'Sora',sans-serif",padding:'1rem',overflowY:'auto'}}>
      <div style={{width:'100%',maxWidth:'520px',animation:'slideUp 0.3s ease'}}>

        {/* 3D Card */}
        {method==='card' && <CardVisual number={card.number} name={card.name} expiry={card.expiry} cvv={card.cvv} flipped={flipped}/>}

        <div style={{background:'#0d0d0d',borderRadius:'24px',padding:'2rem',boxShadow:'0 20px 60px rgba(0,0,0,0.8)',border:'1px solid rgba(255,255,255,0.08)'}}>

          {/* Header */}
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1.5rem'}}>
            <div>
              <p style={{color:'#555',fontSize:'0.72rem',fontWeight:'600',letterSpacing:'1px',textTransform:'uppercase',margin:'0 0 4px',fontFamily:"'Sora',sans-serif"}}>🔒 SECURE PAYMENT</p>
              <p style={{color:GOLD,fontWeight:'700',fontSize:'1.3rem',margin:0,fontFamily:"'Space Mono',monospace"}}>₹{amount.toLocaleString()}</p>
            </div>
            <button onClick={onClose} style={{background:'#1a1a1a',border:'1px solid rgba(255,255,255,0.1)',color:'#666',borderRadius:'8px',width:'32px',height:'32px',cursor:'pointer',fontFamily:T,fontSize:'1rem'}}>✕</button>
          </div>

          {/* Method tabs */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:'8px',marginBottom:'1.8rem'}}>
            {[['card','💳 Card'],['upi','📱 UPI'],['netbanking','🏦 Net Banking']].map(([id,label])=>(
              <button key={id} onClick={()=>{setMethod(id);setErrors({});}}
                style={{padding:'10px 4px',borderRadius:'12px',border:`2px solid ${method===id?GOLD:'rgba(255,255,255,0.08)'}`,background:method===id?'rgba(212,175,55,0.1)':'#111',color:method===id?GOLD:'#555',fontWeight:'600',fontSize:'0.76rem',cursor:'pointer',fontFamily:"'Sora',sans-serif",transition:'all 0.2s'}}>
                {label}
              </button>
            ))}
          </div>

          {/* ── Card Fields ── */}
          {method==='card' && (
            <div style={{display:'flex',flexDirection:'column',gap:'1rem'}}>
              <div>
                <label style={lbl}>CARD NUMBER</label>
                <input value={card.number} onChange={e=>setCard(p=>({...p,number:formatCard(e.target.value)}))} placeholder="1234 5678 9012 3456" maxLength={19} style={inp(errors.number)}
                  onFocus={e=>e.target.style.borderColor=GOLD} onBlur={e=>e.target.style.borderColor=errors.number?'#FF453A':'rgba(255,255,255,0.1)'}/>
                {errors.number && <p style={{color:'#FF453A',fontSize:'0.72rem',margin:'4px 0 0'}}>{errors.number}</p>}
              </div>
              <div>
                <label style={lbl}>CARDHOLDER NAME</label>
                <input value={card.name} onChange={e=>setCard(p=>({...p,name:e.target.value}))} placeholder="As printed on card" style={inp(errors.name)}
                  onFocus={e=>e.target.style.borderColor=GOLD} onBlur={e=>e.target.style.borderColor=errors.name?'#FF453A':'rgba(255,255,255,0.1)'}/>
                {errors.name && <p style={{color:'#FF453A',fontSize:'0.72rem',margin:'4px 0 0'}}>{errors.name}</p>}
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'12px'}}>
                <div>
                  <label style={lbl}>EXPIRY DATE</label>
                  <input value={card.expiry} onChange={e=>setCard(p=>({...p,expiry:formatExpiry(e.target.value)}))} placeholder="MM/YY" maxLength={5} style={inp(errors.expiry)}
                    onFocus={e=>e.target.style.borderColor=GOLD} onBlur={e=>e.target.style.borderColor=errors.expiry?'#FF453A':'rgba(255,255,255,0.1)'}/>
                  {errors.expiry && <p style={{color:'#FF453A',fontSize:'0.72rem',margin:'4px 0 0'}}>{errors.expiry}</p>}
                </div>
                <div>
                  <label style={lbl}>CVV / CVC</label>
                  <input value={card.cvv} onChange={e=>setCard(p=>({...p,cvv:e.target.value.replace(/\D/g,'').slice(0,4)}))} placeholder="•••" maxLength={4} type="password" style={inp(errors.cvv)}
                    onFocus={e=>{setFlipped(true);e.target.style.borderColor=GOLD;}} onBlur={e=>{setFlipped(false);e.target.style.borderColor=errors.cvv?'#FF453A':'rgba(255,255,255,0.1)';}}/>
                  {errors.cvv && <p style={{color:'#FF453A',fontSize:'0.72rem',margin:'4px 0 0'}}>{errors.cvv}</p>}
                </div>
              </div>
            </div>
          )}

          {/* ── UPI ── */}
          {method==='upi' && (
            <div>
              <p style={{...lbl,marginBottom:'10px'}}>CHOOSE UPI APP</p>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'10px',marginBottom:'1.2rem'}}>
                {UPI_APPS.map(app=>(
                  <button key={app.id} onClick={()=>{setUpiApp(app.id);setErrors({});}}
                    style={{padding:'14px',borderRadius:'14px',border:`2px solid ${upiApp===app.id?app.color:'rgba(255,255,255,0.08)'}`,background:upiApp===app.id?`${app.color}18`:'#111',cursor:'pointer',fontFamily:"'Sora',sans-serif",fontWeight:'600',fontSize:'0.85rem',color:upiApp===app.id?app.color:'#555',transition:'all 0.2s',display:'flex',alignItems:'center',justifyContent:'center',gap:'8px'}}>
                    {app.emoji} {app.label}
                  </button>
                ))}
              </div>
              <div style={{display:'flex',alignItems:'center',gap:'12px',margin:'1rem 0'}}>
                <div style={{flex:1,height:'1px',background:'rgba(255,255,255,0.07)'}}/>
                <span style={{color:'#333',fontSize:'0.75rem',fontWeight:'600',fontFamily:"'Sora',sans-serif"}}>OR</span>
                <div style={{flex:1,height:'1px',background:'rgba(255,255,255,0.07)'}}/>
              </div>
              <label style={lbl}>ENTER UPI ID MANUALLY</label>
              <input value={upiId} onChange={e=>{setUpiId(e.target.value);setErrors({});}} placeholder="name@upi" style={inp(errors.upi)}
                onFocus={e=>e.target.style.borderColor=GOLD} onBlur={e=>e.target.style.borderColor='rgba(255,255,255,0.1)'}/>
              {errors.upi && <p style={{color:'#FF453A',fontSize:'0.72rem',margin:'4px 0 0'}}>{errors.upi}</p>}
            </div>
          )}

          {/* ── Net Banking ── */}
          {method==='netbanking' && (
            <div>
              <label style={lbl}>SELECT YOUR BANK</label>
              <div style={{display:'flex',flexDirection:'column',gap:'8px',maxHeight:'260px',overflowY:'auto'}}>
                {BANKS.map(b=>(
                  <button key={b} onClick={()=>{setBank(b);setErrors({});}}
                    style={{padding:'13px 16px',borderRadius:'12px',border:`2px solid ${bank===b?GOLD:'rgba(255,255,255,0.07)'}`,background:bank===b?'rgba(212,175,55,0.1)':'#111',cursor:'pointer',fontFamily:"'Sora',sans-serif",fontWeight:'500',fontSize:'0.85rem',color:bank===b?GOLD:'#666',textAlign:'left',transition:'all 0.2s',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                    🏦 {b} {bank===b && <span style={{color:GOLD,fontWeight:'700'}}>✓</span>}
                  </button>
                ))}
              </div>
              {errors.bank && <p style={{color:'#FF453A',fontSize:'0.72rem',margin:'8px 0 0'}}>{errors.bank}</p>}
            </div>
          )}

          {/* Total */}
          <div style={{background:'#111',borderRadius:'12px',padding:'12px 16px',margin:'1.4rem 0',display:'flex',justifyContent:'space-between',alignItems:'center',border:'1px solid rgba(255,255,255,0.05)'}}>
            <span style={{color:'#555',fontSize:'0.83rem',fontFamily:"'Sora',sans-serif"}}>Total Amount</span>
            <span style={{color:GOLD,fontWeight:'700',fontSize:'1.1rem',fontFamily:"'Space Mono',monospace"}}>₹{amount.toLocaleString()}</span>
          </div>

          {/* Pay button */}
          <button onClick={handlePay} style={{width:'100%',padding:'16px',background:GOLD,color:'#000',border:'none',borderRadius:'14px',cursor:'pointer',fontWeight:'700',fontSize:'1rem',fontFamily:"'Sora',sans-serif",boxShadow:'0 8px 24px rgba(212,175,55,0.35)',letterSpacing:'0.5px',animation:'pulse 2s ease infinite'}}>
            🔒 Pay ₹{amount.toLocaleString()}
          </button>
          <p style={{textAlign:'center',color:'#333',fontSize:'0.7rem',marginTop:'0.8rem',fontFamily:"'Sora',sans-serif"}}>🔐 256-bit SSL Encrypted • Safe &amp; Secure</p>
        </div>

        <button onClick={onClose} style={{width:'100%',padding:'12px',background:'transparent',color:'#444',border:'none',cursor:'pointer',fontSize:'0.85rem',fontFamily:"'Sora',sans-serif",marginTop:'1rem',fontWeight:'500'}}>
          ← Cancel &amp; Go Back
        </button>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════
   MyBookings main component
═══════════════════════════════════════ */
export default function MyBookings() {
  const [bookings, setBookings]       = useState([]);
  const [loading, setLoading]         = useState(true);
  const [payingBooking, setPayingBooking] = useState(null);
  const [filter, setFilter]           = useState('all');

  useEffect(() => { fetchBookings(); }, []);

  const fetchBookings = async () => {
    try {
      const res = await API.get('/bookings/my-bookings');
      setBookings(res.data?.bookings || res.data || []);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const cancel = async (id) => {
    if (!window.confirm('Cancel this booking?')) return;
    try {
      await API.patch(`/bookings/${id}/cancel`);
      fetchBookings();
    } catch { alert('Failed to cancel.'); }
  };

  const filtered = filter === 'all' ? bookings : bookings.filter(b => b.status === filter);

  const STATUS_COLOR = {
    confirmed: { bg:'rgba(48,209,88,0.1)',  color:'#30D158', border:'rgba(48,209,88,0.2)' },
    pending:   { bg:'rgba(255,214,10,0.1)', color:'#FFD60A', border:'rgba(255,214,10,0.2)' },
    cancelled: { bg:'rgba(255,69,58,0.1)',  color:'#FF453A', border:'rgba(255,69,58,0.2)' },
    booked:    { bg:'rgba(48,209,88,0.1)',  color:'#30D158', border:'rgba(48,209,88,0.2)' },
  };

  return (
    <div style={{ background:'#000', minHeight:'100vh', fontFamily: T, color:'#fff', padding:'2.5rem' }}>
      <style>{ANIM}</style>

      {/* Header */}
      <div style={{ marginBottom:'2.5rem' }}>
        <p style={{ color:GOLD, fontSize:'0.72rem', fontWeight:700, letterSpacing:'2px', textTransform:'uppercase', margin:'0 0 6px' }}>Account</p>
        <h1 style={{ color:'#fff', fontWeight:700, fontSize:'2rem', margin:0, letterSpacing:'-1px' }}>My Bookings</h1>
      </div>

      {/* Filters */}
      <div style={{ display:'flex', gap:'4px', marginBottom:'2rem', background:'#0d0d0d', borderRadius:'12px', padding:'4px', border:'1px solid rgba(255,255,255,0.06)', width:'fit-content' }}>
        {['all','confirmed','pending','cancelled'].map(f=>(
          <button key={f} onClick={()=>setFilter(f)} style={{ padding:'8px 18px', borderRadius:'9px', border:'none', cursor:'pointer', fontWeight:600, fontSize:'0.82rem', fontFamily:T, textTransform:'capitalize', background:filter===f?GOLD:'transparent', color:filter===f?'#000':'#555', transition:'all 0.2s' }}>
            {f}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{ display:'flex', alignItems:'center', justifyContent:'center', minHeight:'40vh' }}>
          <div style={{ width:'36px', height:'36px', border:'2px solid #222', borderTopColor:GOLD, borderRadius:'50%', animation:'spin 0.8s linear infinite' }}/>
        </div>
      ) : filtered.length === 0 ? (
        <div style={{ textAlign:'center', padding:'5rem', color:'#333' }}>
          <p style={{ fontSize:'2rem', marginBottom:'1rem' }}>◈</p>
          <p style={{ color:'#555', fontWeight:600 }}>No bookings found</p>
        </div>
      ) : (
        <div style={{ display:'flex', flexDirection:'column', gap:'12px', animation:'fadeUp 0.4s ease' }}>
          {filtered.map((b, i) => {
            const sc     = STATUS_COLOR[b.status] || STATUS_COLOR.pending;
            const amount = b.totalAmount || b.totalPrice || b.amount || 0;
            return (
              <div key={b._id||i} style={{ background:'#0d0d0d', border:'1px solid rgba(255,255,255,0.07)', borderRadius:'16px', padding:'1.4rem', display:'flex', alignItems:'center', gap:'1.5rem', flexWrap:'wrap' }}>
                <div style={{ flex:1, minWidth:'200px' }}>
                  <h3 style={{ color:'#fff', fontWeight:700, fontSize:'0.97rem', margin:'0 0 6px' }}>{b.event?.name||b.eventName||'Event'}</h3>
                  <div style={{ display:'flex', gap:'1.5rem', flexWrap:'wrap' }}>
                    {b.event?.date && <span style={{ color:'#555', fontSize:'0.8rem' }}>📅 {new Date(b.event.date).toLocaleDateString('en-IN')}</span>}
                    <span style={{ color:'#555', fontSize:'0.8rem' }}>🎫 {b.quantity||1} ticket{(b.quantity||1)>1?'s':''}</span>
                    {amount > 0 && <span style={{ color:GOLD, fontSize:'0.82rem', fontWeight:700 }}>₹{amount.toLocaleString()}</span>}
                  </div>
                </div>
                <div style={{ display:'flex', alignItems:'center', gap:'10px', flexWrap:'wrap' }}>
                  <span style={{ padding:'5px 12px', borderRadius:'20px', fontSize:'0.72rem', fontWeight:700, background:sc.bg, color:sc.color, border:`1px solid ${sc.border}`, textTransform:'uppercase' }}>{b.status}</span>
                  {(b.status==='pending'||b.status==='booked') && amount>0 && (
                    <button onClick={()=>setPayingBooking(b)} style={{ padding:'8px 18px', background:GOLD, color:'#000', border:'none', borderRadius:'8px', cursor:'pointer', fontWeight:700, fontSize:'0.82rem', fontFamily:T }}>Pay Now</button>
                  )}
                  {b.status !== 'cancelled' && (
                    <button onClick={()=>cancel(b._id)} style={{ padding:'8px 16px', background:'transparent', color:'#FF453A', border:'1px solid rgba(255,69,58,0.2)', borderRadius:'8px', cursor:'pointer', fontWeight:600, fontSize:'0.82rem', fontFamily:T, transition:'background 0.2s' }}
                      onMouseEnter={e=>e.currentTarget.style.background='rgba(255,69,58,0.08)'}
                      onMouseLeave={e=>e.currentTarget.style.background='transparent'}>
                      Cancel
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {payingBooking && (
        <PaymentModal
          booking={payingBooking}
          onClose={()=>setPayingBooking(null)}
          onSuccess={fetchBookings}
        />
      )}
    </div>
  );
}
